  const MANUAL_CATEGORY_RULES = {
    "tuoitre.vn": [],
    "thanhnien.vn": []
  };

  function findManualCategoryRule(sourceHost, slug1, slug2, payload) {
    const rules = MANUAL_CATEGORY_RULES[sourceHost] || [];
    const s1 = (slug1 || '').trim().toLowerCase();
    const s2 = (slug2 || '').trim().toLowerCase();

    for (const rule of rules) {
      if (!rule) continue;
      if (typeof rule.match === 'function') {
        try {
          if (rule.match({ slug1: s1, slug2: s2, payload, sourceHost })) return rule;
        } catch (_) {}
        continue;
      }

      if (rule.slug1 && s1 !== rule.slug1) continue;
      if (rule.slug2 && s2 !== rule.slug2) continue;
      if (Array.isArray(rule.slug1In) && !rule.slug1In.includes(s1)) continue;
      if (Array.isArray(rule.slug2In) && !rule.slug2In.includes(s2)) continue;
      return rule;
    }
    return null;
  }

